// PUT: Replaces the whole user
fetch('/api/users/1', { method: 'PUT', body: JSON.stringify({name: 'Bob', age: 30}) });

// PATCH: Only updates the age, leaves name alone
fetch('/api/users/1', { method: 'PATCH', body: JSON.stringify({age: 31}) });
